package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.mockito.Mockito.mock;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testValidate() throws Exception {
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        assertThrows(IllegalArgumentException.class, () -> {
            csvFormat.validate();
        });

        CSVFormat csvFormat2 = new CSVFormat(',', ',', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        assertThrows(IllegalArgumentException.class, () -> {
            csvFormat2.validate();
        });

        CSVFormat csvFormat3 = new CSVFormat(',', '"', '"', null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        assertThrows(IllegalArgumentException.class, () -> {
            csvFormat3.validate();
        });

        CSVFormat csvFormat4 = new CSVFormat(',', '"', null, '"', null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        assertThrows(IllegalArgumentException.class, () -> {
            csvFormat4.validate();
        });

        CSVFormat csvFormat5 = new CSVFormat(',', '"', '"', '"', null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        assertThrows(IllegalArgumentException.class, () -> {
            csvFormat5.validate();
        });

        CSVFormat csvFormat6 = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        assertThrows(IllegalArgumentException.class, () -> {
            csvFormat6.validate();
        });

        CSVFormat csvFormat7 = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);
        csvFormat7.withHeader("A", "B", "A");

        assertThrows(IllegalArgumentException.class, () -> {
            csvFormat7.validate();
        });
    }
}
